import { combineReducers } from "redux"
import cartReducer, { cartReducerActions } from "./cartReducer"
import { createStore } from "redux"
import { cartReducer_i } from "./cartReducer"

export default createStore(combineReducers({ cartReducer }))
export const storeActions = { cartReducerActions }
export interface storeRootState {
  cartReducer: cartReducer_i
}
